var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"여러분, 괜찮으십니까?","JPN":"皆さん、ご無事ですか？","ENG":"Is everyone okay?","TWN":"大家，你們沒事吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아, 네. 저희는 다치지 않았어요. 그런데 레아가…….","JPN":"あ、はい。私たちは大丈夫です。でもレアが……","ENG":"Oh, yes. We’re fine, but Leah...","TWN":"嗯，我們沒事，可是蕾亞她……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"왜…… 그러세요? 제 얼굴이 뭔가 이상한가요?","JPN":"どうか……しましたか？　私の顔に何か？","ENG":"Why are you looking at me like that? Is there something weird on my face?","TWN":"你……為什麼那樣盯著我？我臉上有東西嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"아, 아닙니다. 제가 개인적으로 존경하는 분과 닮으셔서요.","JPN":"あ、いいえ。私が個人的に尊敬している方と似ていらっしゃるので。","ENG":"Oh, it’s nothing. You remind me of someone I admire.","TWN":"沒…沒事，只是你長得很像我很尊敬的一個人。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"여긴 교전에 휘말릴 수 있습니다. 저희 수송기로 이동하시죠.","JPN":"ここでは交戦に巻き込まれるかも知れません。私たちの輸送機へ移動しましょう。","ENG":"This place isn’t safe. We must get to the transport.","TWN":"在這裡會有危險，搭我們的運輸機離開吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"집으로…… 가면 안 돼요? 집에 가야 하는데……. 우리 딸애가 기다리고 있을 거야…….","JPN":"家に……行きたいです。家に帰らないと……娘が待ってるはずよ……","ENG":"Can’t we go... Home? I need to go home... My daughter will be waiting for me...","TWN":"我可以……回家嗎？我要回家……我女兒在家等我……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니, 정신 차려요! 따님은 지금 만신창이가 되어 있다고요!","JPN":"おばさん、しっかりして！　娘さんは今ボロボロになってますから！","ENG":"Madam, get a hold of yourself! Your daughter needs immediate medical attention!","TWN":"伯母，你冷靜點！妳女兒現在傷得很重！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"만신창이라니……. 엄마 걱정시키지는 마, 중사…….","JPN":"ボロボロって……お母さんが心配するじゃない、軍曹……","ENG":"Medical attention? ...Don’t make Mom worry, Sergeant.","TWN":"什麼傷得很重……中士，你不要亂說話嚇我媽……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"쿨럭……! 그런데 당신들은, 평범한 용병은 아닌 것 같은데…….","JPN":"ゴホッ……！　ところで君たちは、ただの傭兵ではなさそうだけど……","ENG":"*Cough!* But, you guys don’t look like ordinary mercenaries...","TWN":"咳咳……！你們感覺不像是普通的傭兵……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"관리국 직속 오피셜 서포트라고 알아 두시면 됩니다.","JPN":"管理局直属のオフィシャルサポートだと思ってください。","ENG":"We are called the Official Support, sent directly by the Administration.","TWN":"就當我們是管理局直屬的官方支援吧。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"자, 수송기 내부에 의료 설비가 갖춰져 있습니다. 절 따라오십시오.","JPN":"さあ、輸送機の内部に医療設備が備えられています。私についてきてください。","ENG":"There’s medical equipment in the transport. Follow me.","TWN":"跟我來，運輸機裡有醫療設備。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이런, 예고르. 에스코트하는 데 방해됐으려나.","JPN":"あら、イェゴール。エスコートの邪魔をしたかしら？","ENG":"Ah, Yegor. Did I bother you in the middle of the escort?","TWN":"可惡，伊高爾，我有妨礙到你嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님?! 어디 안 다치셨습니까?","JPN":"副戦隊長！？　お怪我はありませんか？","ENG":"Deputy Commander?! Are you hurt?","TWN":"副戰隊長？！有沒有哪裡受傷？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"새삼스럽게. 이래봬도 카운터야. 한 대 정도 허용한다고 치명상까지 입진 않아.","JPN":"何を改まって。こう見えてもカウンターよ。一撃くらい食らっても致命傷にはならないわ。","ENG":"No problem. I’m a Counter. Such wounds won’t be enough to kill me.","TWN":"緊張什麼！我可是制裁者呢，被打幾下也不至於傷得多嚴重啦～"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇지만……. 상대가 소문 이상이긴 하네.","JPN":"でも……相手は想像以上だったわね。","ENG":"But still... Looks like she was more than just a rumor.","TWN":"不過……她比傳聞中還厲害呢！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 망령된 몰골……. 선명하게 기억하고 있도다.","JPN":"あの亡霊たる姿……鮮明に覚えておる。","ENG":"That irrational appearance... I remember it clearly now.","TWN":"你的臉……我記得一清二楚呢。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"주인을 감싸고자 내 앞을 가로막는 것이냐. 복제품.","JPN":"主人を庇うために私の前に立つのか？　複製品よ。","ENG":"You are standing in my way for the sake of your master, clone.","TWN":"你擋住我的去路是想包庇主人嗎，複製品？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"읏……! 저 괴물, 그렇게 날뛰고도 멀쩡하잖아……?","JPN":"うっ……！　あの化け物、あんなに暴れてたのにピンピンしてるじゃない……？","ENG":"Ugh...! That monster! After all that and there’s not a scratch on her.","TWN":"呃……！那個怪物怎麼一點事也沒有……？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다짜고짜 민감한 곳을 찌르다니 아쉬운걸. 실패작이라고 안 불러서 고마워 해야 하나?","JPN":"いきなり敏感なところを突いてくるなんて、残念ね。失敗作呼ばわりしないことに感謝すべきなのかしら？","ENG":"Saying such a mean thing suddenly without cause. That hurts. I guess I should thank you for not calling me a failed product?","TWN":"真可惜，虧我專挑敏感的地方攻擊。我該謝謝你沒叫我失敗品嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 공격은 통했습니까?","JPN":"副戦隊長、攻撃は通じましたか？","ENG":"Deputy Commander, does your attack work?","TWN":"副戰隊長，攻擊有效嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"전혀. 갑옷이 너무 단단해. 우리 애들한테도 입혀 주고 싶을 정도로.","JPN":"いや、全然。鎧が固すぎるの。うちの子どもたちに着せたいくらいにね。","ENG":"Not at all. That armor is too powerful. I want that kind of armor for our kids.","TWN":"完全沒有，她的鎧甲超堅固，堅固到我都想拿來給你們穿。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"걱정해 주시는 건 감사하지만 지금은 참으시죠.","JPN":"ご心配はありがたいのですが、今は我慢してください。","ENG":"I appreciate you thinking about us, but please focus on the present situation.","TWN":"謝謝副隊長這種時候還這麼顧慮我們，但現在還是先忍著吧。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"화력이 필요하신 것 같은데, 도와 드릴까요?","JPN":"火力が必要そうですが、手伝いましょうか？","ENG":"It looks like you need additional firepower, shall I provide assistance?","TWN":"你們的火力似乎不太夠，需要我幫忙嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_12"},{"id":"L39_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"모네카? 어떻게 말이지?","JPN":"モネカ？　どうやって手伝うんだ？","ENG":"Moneka? What kind of help?","TWN":"莫奈卡？你打算怎麼做？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"고정포대로 사용 중인 에스타크들을 해킹으로 장악하면 잠시 사용할 수 있을 거예요.","JPN":"固定砲台で使用しているエスタークをハッキングで掌握すれば、しばらく使えるはずです。","ENG":"If I hack into the Estaques, currently being used as a turret, I might be able to control it for some time.","TWN":"只要駭入作為固定砲台使用的艾斯塔克，應該可以暫時納為己用。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"최대 출력으로는 한 번밖에 못 쏘겠지만, 4문이나 되니까 화력은 충분하지 않을까요?","JPN":"最大出力では一回しか撃てませんけど、4台もありますから火力は十分じゃないでしょうか？","ENG":"Only once at maximum power, but shouldn’t that be enough?","TWN":"最大火力只能使用一次，但有4門，火力應該夠吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋은 아이디어네. 허락할게.","JPN":"いいアイデアね。許可する。","ENG":"Good idea. Permission granted.","TWN":"很棒的點子，批准！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 그러다가 자칫 잘못하면 외교적인 문제로 비화될 수도 있습니다.","JPN":"副戦隊長、一歩間違えれば外交問題となりかねません。","ENG":"Deputy Commander, doing that could cause diplomatic issues.","TWN":"副戰隊長，萬一有個差池，很可能會引發外交問題。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"외교 문제 따지다가 도시 전체가 쑥대밭이 되면?","JPN":"外交がどうこう言っているうちに、街全体が廃墟になったらどうするの？","ENG":"But what if the entire city is destroyed while we wait for permission?","TWN":"所以你因為顧慮外交問題，要眼睜睜看著城市變成一片廢墟嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그이도 우릴 보낼 때 이 정도는 예상했을 거야. 책임을 져도 내가 질 테니까 시작해.","JPN":"彼も私たちを送った時このくらいは予想したはずよ。私が責任を持つから始めなさい。","ENG":"He would have foreseen this possibility when sending us. I’ll take responsibility, so begin immediately.","TWN":"他派我們來時，應該也有料想到這個情況，責任我來擔，開始！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"감사합니다, 부전대장님! 그럼 조금만 시간을 벌어 주세요!","JPN":"ありがとうございます、副戦隊長！　それじゃあちょっとだけ時間を稼いでくださいね！","ENG":"Thank you, Deputy Commander! It will only take a moment!","TWN":"謝謝副戰隊長！麻煩請幫我爭取些時間！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"제일 부담스러운 부탁을 받았네. 의욕이 생기는걸.","JPN":"一番難しいこと頼まれちゃったわ。やる気が出るね。","ENG":"What a burdensome request this time. I’m actually starting to have fun.","TWN":"如此重責大任，感覺有點興奮呢！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"어쩔 수 없죠. 부전대장님은 어려운 부탁일수록 더 구미가 당기시니 말입니다.","JPN":"仕方ありません。副戦隊長は難しい頼みであるほど興味が湧きますから。","ENG":"You can’t help it, can you? The more difficult the request, the more you get pulled in.","TWN":"沒辦法，越困難的任務，副戰隊長就越興奮。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……잠깐, 기다려.","JPN":"……ちょっと、待って。","ENG":"...Hold on, wait.","TWN":"……先等一下。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아! 움직이면 안 돼!","JPN":"レア、動いちゃダメ！","ENG":"Leah! Don’t move!","TWN":"蕾亞！你別亂動！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저 녀석은 나를 노리고 왔어. 구경이나 할 때가 아니야.","JPN":"あいつの狙いは私なの。見ている場合じゃないよ。","ENG":"That bastard came here for me. I can’t just stand around and watch.","TWN":"那傢伙是針對我來的，我怎麼可以袖手旁觀！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사, 내가 부탁한 일 마저 해 줄 수 있지?","JPN":"軍曹、私が頼んだことお願いね？","ENG":"Sergeant, do you think you can finish what I asked?","TWN":"中士，我拜託你的事，你做得到吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨, 그렇지만…….","JPN":"レアさん、でも……","ENG":"But Leah...","TWN":"蕾亞小姐，可是……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"괜찮아. 싸우지 않아도 돼. 그렇게 효율적이지는 않은 짓이잖아.","JPN":"大丈夫。戦わなくていい。あまり効率的じゃないんだし。","ENG":"It’s fine. You don’t have to fight. It won’t be the most efficient way.","TWN":"放心，不用戰鬥，畢竟那很沒效率。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저는 효율을 중시하는 편이거든요.","JPN":"私は効率を重視する方ですから。","ENG":"I just like doing things as efficiently as possible.","TWN":"我是重視效率的人。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"혹시 모를 교전에 대비해 체력을 아껴야죠. 조수 일은 정중하게 사양하겠습니다.","JPN":"もしもの交戦に備えて体力を保っておかないと。助手の仕事はご丁寧にお断りします。","ENG":"I need to save my strength for a possible confrontation. I'd like to decline your assistance.","TWN":"我要保留體力，這樣之後萬一遇到敵人才有體力開戰，請恕我拒絕當你的小助手。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯嗯……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"억지 부리는 걸 말리진 않겠어. 그렇지만 객기 부리다 짐이 되는 건 용서 안 해.","JPN":"無茶を止めはしないわ。でも羽目を外しすぎて足を引っ張ることは許さないよ。","ENG":"I won’t stop you, but I will not forgive you if you slow me down.","TWN":"我不會阻止你逞英雄，但萬一你造成大家困擾，我可不會原諒你。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"참견해 줘서 고마워, 용병 씨. 노력할게.","JPN":"おせっかいありがとうね、傭兵さん。努力するよ。","ENG":"Thank you for stepping in, Ms. Mercenary. I’ll do what I can as well.","TWN":"謝謝你，傭兵小姐，我會努力的。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……그렇군. 저열한 복제품으로 막아 보겠다는 건가.","JPN":"……さようか。低劣な複製品で止めてみせるつもりか。","ENG":"...I see. You are trying to stop me with a vulgar clone?","TWN":"……是嗎？劣質的複製品打算阻止我嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나…… 이번에는 네 뜻대로 되진 않을 거다……!","JPN":"だが……今度は貴様の思いどおりにはいかん……！","ENG":"However... This time things will not go as you desire...!","TWN":"不過……這次我是不會讓你稱心如意的……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};